import "./App.css";

function App() {
  function connect() {
    if (navigator.onLine) {
      window.location.href = "https://app.amigosapp.nl";
    }
    return false;
  }

  connect();

  function retry() {
    if (!connect()) {
      alert("Can't connect to server");
    }
  }

  return (
    <div className="splash">
      <img src="splash.png" alt="" />

      <h2>There is no connection to the server</h2>

      <button onClick={retry}>Retry</button>
    </div>
  );
}

export default App;
